class Solution {
    public long countGoodIntegers(int n, int k) {
        int count = 0;
        for (int i = 1; i <= n; i++) {
            int num = i;
            while (num > 1) {
                int digitCount = 0;
                while (num % k == 0) {
                    digitCount++;
                    num /= k;
                }
                if (digitCount == k && num == 1) {
                    count++;
                }
                num++;
            }
        }
        return count;
    }
}
```

